#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    int findMinXor(int n, vector<int>& nums)
    {
        int xor = 0;
        for (int i = 0; i < n;
            i++)
        {
            if ((xor | nums[i]) != 0)
                xor ^= nums[i];
        }
        return xor;
    }
};

using namespace std;
int main()
{
    int n; cin >> n;
    vector<int> nums(n); for (int i = 0; i < n; i++) cin >> nums[i];
    Solution obj;
    int ans = obj.findMinXor(n, nums);
    cout << ans << endl;
    return 0;
}
